+        Ok(Self {
+            metadata,
+            predictors,
+            ffns,
+            neuron_cache,
+            config: InferenceConfig::default(),
+            stats: GenerationStats::default(),
+            vocab_size,
+        })
+    }
+
+    /// Create from a GGUF model file
+    #[cfg(not(target_arch = "wasm32"))]
+    pub fn from_gguf(path: &std::path::Path) -> Result<Self> {
+        use std::fs;
+
+        let data = fs::read(path).map_err(|e| {
+            SparseInferenceError::Model(crate::error::ModelError::LoadFailed(e.to_string()))
+        })?;
+
+        Self::from_gguf_bytes(&data)
+    }
+
+    /// Create from GGUF model bytes
+    pub fn from_gguf_bytes(data: &[u8]) -> Result<Self> {
+        let gguf = GgufParser::parse(data)?;
+
+        // Extract model configuration from GGUF metadata
+        let hidden_dim = gguf.metadata.get("llama.embedding_length")
+            .and_then(|v| v.as_u32())
+            .unwrap_or(4096) as usize;
+
+        let intermediate_dim = gguf.metadata.get("llama.feed_forward_length")
+            .and_then(|v| v.as_u32())
+            .unwrap_or((hidden_dim * 4) as u32) as usize;
+
+        let num_layers = gguf.metadata.get("llama.block_count")
+            .and_then(|v| v.as_u32())
+            .unwrap_or(32) as usize;
+
+        let vocab_size = gguf.metadata.get("llama.vocab_size")
+            .and_then(|v| v.as_u32())
