+fn dequantize_q5_k(data: &[u8], n_elements: usize) -> Vec<f32> {
+    dequantize_q5_0(data, n_elements)
+}
+
+fn dequantize_q6_k(data: &[u8], n_elements: usize) -> Vec<f32> {
+    dequantize_q5_0(data, n_elements)
+}
